 /** Convert a Kubernetes memory string (e.g. "128Mi", "1Gi", "512M") to MiB */
 function parseMemoryToMiB(mem: string): number {
-  const GI_TO_MIB = 1024
-  const KI_TO_MIB = 1 / 1024
