+  if (mem.endsWith('G')) return Math.round((parseFloat(mem) || 0) * GB_TO_MIB)
+  if (mem.endsWith('M')) return Math.round((parseFloat(mem) || 0) * MB_TO_MIB)
   return Math.round((parseFloat(mem) || 0) / BYTES_PER_MIB)
